import random

def detect_flakiness(func, n_runs=10):
    results = set()
    for _ in range(n_runs):
        try:
            result = func()
            results.add(result)
        except Exception as e:
            return True  # Non-deterministic if it raises an exception
    return False if len(results) == 1 else True

def flaky_test():
    return random.choice([True, False])

def stable_test():
    return False

def stable_pass():
    return True

def run_tests():
    assert detect_flakiness(flaky_test) == True, "Failed to detect flaky_test"
    assert detect_flakiness(stable_test) == False, "False positive on stable_test"
    assert detect_flakiness(stable_pass) == False, "False positive on stable_pass"
    print("All tests passed!")

run_tests()
