def detect_flakiness(func, n_runs=10):
    results = set()
    for _ in range(n_runs):
        try:
            result = func()
            if isinstance(result, list):
                results.add(tuple(result))
            elif isinstance(result, dict):
                results.add(tuple(sorted(result.items())))
            else:
                results.add(result)
        except Exception as e:
            return True  # Non-deterministic due to errors
    return False if len(results) == 1 else True

def complex_stable_test():
    return [1, 2, 3]

def complex_flaky_test():
    if random.random() > 0.5:
        return [1, 2, 3]
    else:
        return [1, 2, 4]

assert detect_flakiness(complex_stable_test) == False
assert detect_flakiness(complex_flaky_test) == True
